# Python/Flask - Configuración segura de CORS
ALLOWED_ORIGINS = ['https://tudominio.com', 'https://app.tudominio.com']

@app.after_request
def add_cors(response):
    origin = request.headers.get('Origin')
    if origin in ALLOWED_ORIGINS:
        response.headers['Access-Control-Allow-Origin'] = origin
        response.headers['Access-Control-Allow-Credentials'] = 'true'
    return response

# Python/Flask - Configuración de CSP
@app.after_request
def add_csp(response):
    response.headers['Content-Security-Policy'] = (
        "default-src 'self'; "
        "script-src 'self' https://cdn.jsdelivr.net; "
        "style-src 'self' 'unsafe-inline'; "
        "img-src 'self' data: https:;"
    )
    return response

# Python/Flask - Configuración de X-Frame-Options
@app.after_request
def add_frame_options(response):
    response.headers['X-Frame-Options'] = 'DENY'
    return response

# Python/Flask - Configuración de X-Content-Type-Options
@app.after_request
def add_content_type_options(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    return response

# Python/Flask - Configuración de X-XSS-Protection
@app.after_request
def add_xss_protection(response):
    response.headers['X-XSS-Protection'] = '1; mode=block'
    return response

# Python/Flask - Configuración de Referrer-Policy
@app.after_request
def add_referrer_policy(response):
